import java.util.HashSet;
import java.util.Set;

class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class Solution {
    public boolean checkEqualTree(TreeNode root) {
        Set<Integer> seen = new HashSet<>();
        int total = sum(root, seen);
        if (total % 2 == 0) {
            seen.remove(total);
            return seen.contains(total / 2);
        }
        return false;
    }

    private int sum(TreeNode node, Set<Integer> seen) {
        if (node == null) return 0;
        int s = node.val + sum(node.left, seen) + sum(node.right, seen);
        seen.add(s);
        return s;
    }
}
```


